import 'package:flutter/material.dart';import 'package:go_router/go_router.dart';import '../../core/utils/validators.dart';import '../../core/widgets/app_button.dart';import '../../core/widgets/app_text_field.dart';import '../../services/auth_service.dart';
class RegisterScreen extends StatefulWidget{final String? redirect;const RegisterScreen({super.key,this.redirect});@override State<RegisterScreen> createState()=>_RegisterScreenState();}
class _RegisterScreenState extends State<RegisterScreen>{final f=GlobalKey<FormState>(),n=TextEditingController(),m=TextEditingController(),e=TextEditingController(),p=TextEditingController(),cp=TextEditingController();bool loading=false;String? error;@override Widget build(BuildContext c)=>Scaffold(appBar:AppBar(title:const Text('Register')),body:Form(key:f,child:ListView(padding:const EdgeInsets.all(16),children:[AppTextField(controller:n,label:'Full Name',validator:(v)=>Validators.required(v,'Full name')),const SizedBox(height:12),AppTextField(controller:m,label:'Mobile Number',keyboardType:TextInputType.phone,validator:Validators.mobile),const SizedBox(height:12),AppTextField(controller:e,label:'Email',keyboardType:TextInputType.emailAddress,validator:Validators.email),const SizedBox(height:12),AppTextField(controller:p,label:'Password',obscure:true,validator:Validators.password),const SizedBox(height:12),AppTextField(controller:cp,label:'Confirm Password',obscure:true,validator:(v)=>v!=p.text?'Passwords do not match':null),if(error!=null)Text(error!,style:const TextStyle(color:Colors.redAccent)),AppButton(label:'Register',loading:loading,onPressed:()async{if(!f.currentState!.validate())return;setState(()=>loading=true);try{await AuthService().register(fullName:n.text,mobile:m.text,email:e.text,password:p.text);if(c.mounted)c.go(widget.redirect??'/home');}catch(ex){setState(()=>error='Registration failed. The mobile or email may already exist.');}finally{if(mounted)setState(()=>loading=false);}})])));}
